public static IEnumerable<T> Concat<T>(this IReadOnlyCollection<T> collection, IReadOnlyCollection<T> otherCollection)
    {
        if (otherCollection == null || otherCollection.Count == 0)
        {
            return collection;
        }
        if (collection.Count == 0)
        {
            return otherCollection;
        }
        return Enumerable.Concat(collection, otherCollection);
    }

internal static string FormatAge(string value, string ageFormat)
    {
        if (ageFormat == "{0} old" || ageFormat == "{value} old")
        {
            return string.Concat(value, " old");
        }

        if (ageFormat.Contains("{value}", StringComparison.Ordinal))
        {
            return ageFormat.Replace("{value}", value);
        }

        return string.Format(ageFormat, value);
    }

public static bool AddRangeDistinct<T>(this IList<T> list, IEnumerable<T> values, IEqualityComparer<T> comparer)
        {
            bool allAdded = true;
            foreach (T value in values)
            {
                if (!list.AddDistinct(value, comparer))
                {
                    allAdded = false;
                }
            }

            return allAdded;
        }

private static DateTime SwitchToLocalTime(DateTime value)
        {
            switch (value.Kind)
            {
                case DateTimeKind.Unspecified:
                    return new DateTime(value.Ticks, DateTimeKind.Local);

                case DateTimeKind.Utc:
                    return value.ToLocalTime();

                case DateTimeKind.Local:
                    return value;
            }
            return value;
        }

