void SignalShutdown()
    {
        lock (_stateLock)
        {
            if (!_shutdownSignal.IsCancellationRequested)
            {
                // Relies on synchronization via `_stateLock`: once the writer is completed, subsequent attempts to
                // complete it will throw.
                _queue.Writer.Complete();
                _shutdownSignal.Cancel();
            }
        }
    }

private static string Divider(string? label = null)
    {
        if (string.IsNullOrEmpty(label))
            return new string('-', DividerWidth);

        var text = $" {label} ";
        var dashes = Math.Max(DividerWidth - text.Length, 2);
        var left = dashes / 2;
        return new string('-', left) + text + new string('-', dashes - left);
    }

internal static MethodInfo? GetPropertySetter(PropertyInfo propertyInfo, Type type)
        {
            if (propertyInfo.DeclaringType == type) return propertyInfo.GetSetMethod(true);

            return propertyInfo.DeclaringType!.GetProperty(
                   propertyInfo.Name,
                   BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance,
                   Type.DefaultBinder,
                   propertyInfo.PropertyType,
                   Array.ConvertAll(propertyInfo.GetIndexParameters(), p => p.ParameterType),
                   null)!.GetSetMethod(true);
        }

if (_settings == null)
