for (var i = _localReminderScheduleWaiters.Count - 1; i >= 0; i--)
        {
            var waiter = _localReminderScheduleWaiters[i];
            if (!IsLocalReminderScheduleReadyCore(waiter.GrainId, waiter.ReminderName))
