if (_waiters.TryGetValue(kvp.Key, out var waiters))
        {
            List<EventWaiter> waitersSnapshot;
            lock (waiters)
            {
                waitersSnapshot = [.. waiters];
            }

            foreach (var waiter in waitersSnapshot)
            {
                if (waiter.TrySetResult(evt))
                {
                    RemoveWaiter(kvp.Key, waiter);
                }
            }
        }

try
        {
            if (client is not null)
            {
                await client.StopAsync().ConfigureAwait(false);
            }
        }
        catch (Exception exc)
        {
            WriteLog("Exception stopping client: {0}", exc);
        }
        finally
        {
            await DisposeAsync(client).ConfigureAwait(false);
            ClientHost = null;
        }

if (client != null)
        {
            var cancelled = new CancellationTokenSource();
            cancelled.Cancel();
            try
            {
                await client.StopAsync(cancelled.Token).ConfigureAwait(false);
            }
            finally
            {
                await DisposeAsync(client);
                ClientHost = null;
