                string deprecationWarning = string.Format(
                    Constants.Runner.NodeMigration.LinuxArm32DeprecationMessage,
                    effectiveDate);

                if (string.Equals(preferredVersion, Constants.Runner.NodeMigration.Node24, StringComparison.OrdinalIgnoreCase))
                {
                    return (Constants.Runner.NodeMigration.Node20, deprecationWarning);
                }

                return (preferredVersion, deprecationWarning);
            }

if (ex is TaskAgentNotFoundException ||
                ex is TaskAgentPoolNotFoundException ||
                ex is TaskAgentSessionExpiredException ||
                ex is AccessDeniedException ||
                ex is RunnerNotFoundException ||
                ex is VssUnauthorizedException)
            {
                Trace.Info($"Non-retriable exception: {ex.Message}");
                return false;
            }
            else
            {
                Trace.Info($"Retriable exception: {ex.Message}");
                return true;
            }

if (unknowns.Count == 0)
            {
                // detect unknown flags and args for valid commands
                foreach (var command in _parser.Commands)
                {
                    if (validOptions.TryGetValue(command, out string[] options))
                    {
                        unknowns.AddRange(_parser.Flags.Where(x => !options.Contains(x, StringComparer.OrdinalIgnoreCase) && !genericOptions.Contains(x, StringComparer.OrdinalIgnoreCase)));
                        unknowns.AddRange(_parser.Args.Keys.Where(x => !options.Contains(x, StringComparer.OrdinalIgnoreCase)));
                    }
                }
            }

if (string.Equals(".dll", originalFileInfo.Extension))
            {
                if (System.Runtime.InteropServices.RuntimeInformation.IsOSPlatform(OSPlatform.Windows))
                {
                    target = new FileInfo(Path.GetFileNameWithoutExtension(originalFileInfo.FullName) + ".exe");
                }
                else
                {
                    // On unix-like operating systems, executables generally do not have an extension.
                    target = new FileInfo(Path.GetFileNameWithoutExtension(originalFileInfo.FullName));
                }
            }
            else
            {
                target = originalFileInfo;
            }

try
            {
                //This process handle returns immediately.
                using(var process = Process.Start(CreateProcessArguments("start")))
                {
                    if (process == null) return false;
                    process.WaitForExit();
                    return process.ExitCode == 0;
                }
            }
            catch
            {
                return false;
            }

try
            {
                //This process handle returns immediately.
                using(var process = Process.Start(CreateProcessArguments("stop")))
                {
                    process.WaitForExit();
                    return process.ExitCode == 0;
                }
            }
            catch
            {
                return false;
            }

if (depth < options.MaxDepth && random.NextDouble() < RecursionProbability)
            {
                switch (random.Next(2))
                {
                    case 0:
                        return await Recurse(options, depth, stack, random, 10, ! options.AvoidDeadlocks, maxgrain, stopAfter);
                    case 1:
                        return await Recurse(options, depth, stack, random, 10, false, maxgrain, stopAfter);
                    case 2:
                        return await Recurse(options, depth, stack, random, 3, false, maxgrain, stopAfter);
                }
            }

[UnconditionalSuppressMessage("Trimming", "IL2070",
        Justification = "KeyValuePair<TKey, TValue> is a BCL type whose Key and Value properties define its public contract and are preserved by the trimmer.")]
    private static string FormatKeyValuePair(Type keyValuePairType, object value)
    {
        var key = keyValuePairType.GetProperty("Key")!.GetValue(value, null);
        var v = keyValuePairType.GetProperty("Value")!.GetValue(value, null);
        return $"[{key.ToStringAwesomely()} => {v.ToStringAwesomely()}]";
    }

